// C solution using persistent segment tree (compiled with -std=c99)
#include <stdio.h>
#include <stdlib.h>

#define MAXN 40005
#define MAXLOG 17
#define MAXC 40005
#define MAXNODE (MAXN * 20) // enough for persistent nodes

int N, Q;
int A[MAXN];
int Cv[MAXN];
int head[MAXN], to[2*MAXN], nxt[2*MAXN], ecnt=0;
int parent[MAXN];
int depth[MAXN];
int version[MAXN];

int nodeCnt = 0;
int segL[MAXNODE], segR[MAXNODE];
int segSum[MAXNODE];
int maxC = 0;

int newNode(){
    ++nodeCnt;
    segL[nodeCnt]=segR[nodeCnt]=segSum[nodeCnt]=0;
    return nodeCnt;
}

int update(int prev, int l, int r, int pos){
    int cur = newNode();
    segL[cur]=segL[prev];
    segR[cur]=segR[prev];
    segSum[cur]=segSum[prev]+1;
    if(l!=r){
        int m=(l+r)>>1;
        if(pos<=m) segL[cur]=update(segL[prev],l,m,pos);
        else segR[cur]=update(segR[prev],m+1,r,pos);
    }
    return cur;
}

int query(int node, int l, int r, int ql, int qr){
    if(!node||ql>r||qr<l) return 0;
    if(ql<=l && r<=qr) return segSum[node];
    int m=(l+r)>>1;
    return query(segL[node],l,m,ql,qr)+query(segR[node],m+1,r,ql,qr);
}

void addEdge(int u,int v){
    to[ecnt]=v; nxt[ecnt]=head[u]; head[u]=ecnt++;
    to[ecnt]=u; nxt[ecnt]=head[v]; head[v]=ecnt++;
}

void dfs(int u,int p){
    parent[u]=p;
    depth[u]= (p==0?0:depth[p]+1);
    // compute Cv for u
    int cnt = A[u];
    for(int e=head[u]; e!=-1; e=nxt[e]){
        int v=to[e];
        if(v==p) continue;
        cnt += A[v];
    }
    Cv[u]=cnt;
    if(cnt>maxC) maxC=cnt;
    // build persistent version
    version[u] = update(p?version[p]:0, 0, MAXC, cnt);
    for(int e=head[u]; e!=-1; e=nxt[e]){
        int v=to[e];
        if(v==p) continue;
        dfs(v,u);
    }
}

long long needThreshold(long long K, int s){
    if(s==0) return (long long)1e18; // impossible
    long long need = (K + s*(s+1)/2 - 1) / (s*(s+1)/2); // ceil(K / (s(s+1)/2))
    // we need Cv >= need
    return need;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        scanf("%d", &N);
        for(int i=1;i<=N;i++) scanf("%d", &A[i]);
        for(int i=1;i<=N;i++) head[i]=-1;
        ecnt=0;
        for(int i=0;i<N-1;i++){
            int u,v; scanf("%d %d", &u, &v);
            addEdge(u,v);
        }
        maxC=0; nodeCnt=0; // reset persistent tree
        dfs(1,0);
        scanf("%d", &Q);
        while(Q--){
            int X,Treq,K; scanf("%d %d %d", &X, &Treq, &K);
            int answer = -1;
            // binary search s in [0,200]
            int lo=0, hi=200;
            while(lo<=hi){
                int mid=(lo+hi)/2;
                if(mid==0){ lo=mid+1; continue; }
                long long need = (K + (long long)mid*(mid+1)/2 - 1) / ((long long)mid*(mid+1)/2);
                if(need>maxC){ // no node can satisfy
                    lo=mid+1; continue;
                }
                int cnt = query(version[X], 0, MAXC, (int)need, MAXC);
                if(cnt>=Treq){ answer=mid; hi=mid-1; }
                else lo=mid+1;
            }
            printf("%d\n", answer);
        }
    }
    return 0;
}
